from flask import Flask, request, jsonify
from datetime import datetime, timedelta
from sqlalchemy import create_engine, Column, Integer, String, DateTime, Boolean
from sqlalchemy.orm import sessionmaker
from sqlalchemy.ext.declarative import declarative_base

app = Flask(__name__)

# Database setup
Base = declarative_base()
engine = create_engine('sqlite:///todo.db')
Session = sessionmaker(bind=engine)
session = Session()

# Todo list model
class TodoItem(Base):
    __tablename__ = 'todo_items'

    id = Column(Integer, primary_key=True)
    title = Column(String)
    description = Column(String)
    due_date = Column(DateTime)
    completed = Column(Boolean, default=False)

# API endpoints
@app.route('/todos', methods=['GET'])
def get_todos():
    todos = session.query(TodoItem).all()
    return jsonify([todo.to_dict() for todo in todos])

@app.route('/todos', methods=['POST'])
def create_todo():
    data = request.get_json()
    new_todo = TodoItem(
        title=data['title'],
        description=data['description'],
        due_date=datetime.strptime(data['due_date'], '%Y-%m-%d')
    )
    session.add(new_todo)
    session.commit()
    return jsonify(new_todo.to_dict()), 201

@app.route('/todos/<int:todo_id>', methods=['GET'])
def get_todo(todo_id):
    todo = session.query(TodoItem).get(todo_id)
    if todo:
        return jsonify(todo.to_dict())
    else:
        return jsonify({'error': 'Todo item not found'}), 404

@app.route('/todos/<int:todo_id>', methods=['PUT'])
def update_todo(todo_id):
    todo = session.query(TodoItem).get(todo_id)
    if todo:
        data = request.get_json()
        todo.title = data['title']
        todo.description = data['description']
        todo.due_date = datetime.strptime(data['due_date'], '%Y-%m-%d')
        todo.completed = data['completed']
        session.commit()
        return jsonify(todo.to_dict())
    else:
        return jsonify({'error': 'Todo item not found'}), 404

@app.route('/todos/<int:todo_id>', methods=['DELETE'])
def delete_todo(todo_id):
    todo = session.query(TodoItem).get(todo_id)
    if todo:
        session.delete(todo)
        session.commit()
        return '', 204
    else:
        return jsonify({'error': 'Todo item not found'}), 404

@app.route('/todos/overdue', methods=['GET'])
def get_overdue_todos():
    overdue_todos = session.query(TodoItem).filter(TodoItem.due_date < datetime.now(), TodoItem.completed == False).all()
    return jsonify([todo.to_dict() for todo in overdue_todos])

@app.route('/todos/due_soon', methods=['GET'])
def get_due_soon_todos():
    due_soon_todos = session.query(TodoItem).filter(TodoItem.due_date < datetime.now() + timedelta(days=7), TodoItem.completed == False).all()
    return jsonify([todo.to_dict() for todo in due_soon_todos])

if __name__ == '__main__':
    Base.metadata.create_all(engine)
    app.run(debug=True)

from flask import Flask, request, jsonify
from datetime import datetime, timedelta

app = Flask(__name__)

# Sample database structure
tasks = [
    {"id": 1, "title": "Finish project report", "description": "Write and submit the project report", "due_date": "2023-04-15", "completed": False},
    {"id": 2, "title": "Grocery shopping", "description": "Buy milk, eggs, and bread", "due_date": "2023-04-12", "completed": False},
    {"id": 3, "title": "Call mom", "description": "Check in with mom and see how she's doing", "due_date": "2023-04-14", "completed": True}
]

@app.route('/api/tasks', methods=['GET'])
def get_tasks():
    return jsonify(tasks)

@app.route('/api/tasks', methods=['POST'])
def create_task():
    data = request.get_json()
    new_task = {
        "id": len(tasks) + 1,
        "title": data["title"],
        "description": data["description"],
        "due_date": data["due_date"],
        "completed": False
    }
    tasks.append(new_task)
    return jsonify(new_task), 201

@app.route('/api/tasks/<int:task_id>', methods=['GET'])
def get_task(task_id):
    task = next((t for t in tasks if t["id"] == task_id), None)
    if task:
        return jsonify(task)
    else:
        return jsonify({"error": "Task not found"}), 404

@app.route('/api/tasks/<int:task_id>', methods=['PUT'])
def update_task(task_id):
    data = request.get_json()
    task = next((t for t in tasks if t["id"] == task_id), None)
    if task:
        task["title"] = data["title"]
        task["description"] = data["description"]
        task["due_date"] = data["due_date"]
        task["completed"] = data["completed"]
        return jsonify(task)
    else:
        return jsonify({"error": "Task not found"}), 404

@app.route('/api/tasks/<int:task_id>', methods=['DELETE'])
def delete_task(task_id):
    task = next((t for t in tasks if t["id"] == task_id), None)
    if task:
        tasks.remove(task)
        return jsonify({"message": "Task deleted"}), 204
    else:
        return jsonify({"error": "Task not found"}), 404

@app.route('/api/tasks/progress', methods=['GET'])
def get_progress():
    total_tasks = len(tasks)
    completed_tasks = sum(1 for t in tasks if t["completed"])
    progress = (completed_tasks / total_tasks) * 100 if total_tasks > 0 else 0
    return jsonify({"total_tasks": total_tasks, "completed_tasks": completed_tasks, "progress": progress})

@app.route('/api/tasks/reminders', methods=['GET'])
def get_reminders():
    today = datetime.now().date()
    reminders = [t for t in tasks if not t["completed"] and datetime.strptime(t["due_date"], "%Y-%m-%d").date() <= today + timedelta(days=7)]
    return jsonify(reminders)

if __name__ == '__main__':
    app.run(debug=True)

from flask import Flask, request, jsonify
from datetime import datetime, timedelta
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///todo.db'
db = SQLAlchemy(app)

class TodoItem(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    description = db.Column(db.Text)
    due_date = db.Column(db.DateTime, nullable=False)
    completed = db.Column(db.Boolean, default=False)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(50), unique=True, nullable=False)
    todo_items = db.relationship('TodoItem', backref='user', lazy='dynamic')

@app.route('/api/users', methods=['POST'])
def create_user():
    data = request.get_json()
    user = User(username=data['username'])
    db.session.add(user)
    db.session.commit()
    return jsonify({'id': user.id, 'username': user.username}), 201

@app.route('/api/users/<int:user_id>/todos', methods=['GET', 'POST'])
def manage_todos(user_id):
    user = User.query.get_or_404(user_id)
    if request.method == 'POST':
        data = request.get_json()
        todo = TodoItem(title=data['title'], description=data['description'],
                        due_date=datetime.strptime(data['due_date'], '%Y-%m-%d'),
                        user=user)
        db.session.add(todo)
        db.session.commit()
        return jsonify(todo_to_dict(todo)), 201
    else:
        todos = user.todo_items.all()
        return jsonify([todo_to_dict(todo) for todo in todos])

@app.route('/api/users/<int:user_id>/todos/<int:todo_id>', methods=['GET', 'PUT', 'DELETE'])
def manage_todo(user_id, todo_id):
    user = User.query.get_or_404(user_id)
    todo = TodoItem.query.filter_by(id=todo_id, user=user).first_or_404()
    if request.method == 'PUT':
        data = request.get_json()
        todo.title = data['title']
        todo.description = data['description']
        todo.due_date = datetime.strptime(data['due_date'], '%Y-%m-%d')
        todo.completed = data['completed']
        db.session.commit()
        return jsonify(todo_to_dict(todo))
    elif request.method == 'DELETE':
        db.session.delete(todo)
        db.session.commit()
        return '', 204
    else:
        return jsonify(todo_to_dict(todo))

@app.route('/api/users/<int:user_id>/stats')
def get_user_stats(user_id):
    user = User.query.get_or_404(user_id)
    total_tasks = user.todo_items.count()
    completed_tasks = user.todo_items.filter_by(completed=True).count()
    overdue_tasks = user.todo_items.filter(TodoItem.due_date < datetime.now()).count()
    return jsonify({
        'total_tasks': total_tasks,
        'completed_tasks': completed_tasks,
        'overdue_tasks': overdue_tasks
    })

@app.route('/api/users/<int:user_id>/reminders')
def get_user_reminders(user_id):
    user = User.query.get_or_404(user_id)
    reminders = user.todo_items.filter(TodoItem.due_date >= datetime.now(),
                                      TodoItem.due_date < datetime.now() + timedelta(days=7),
                                      TodoItem.completed == False).all()
    return jsonify([todo_to_dict(todo) for todo in reminders])

def todo_to_dict(todo):
    return {
        'id': todo.id,
        'title': todo.title,
        'description': todo.description,
        'due_date': todo.due_date.strftime('%Y-%m-%d'),
        'completed': todo.completed
    }

if __name__ == '__main__':
    app.run(debug=True)

