            todos = self.db.get_all_todos()
            return [todo.to_dict() for todo in todos]

    def post(self):
        parser = reqparse.RequestParser()
        parser.add_argument('title', required=True)
        parser.add_argument('description', default='')
        parser.add_argument('due_date', type=lambda x: datetime.strptime(x, '%Y-%m-%d'))
        args = parser.parse_args()

        todo = self.db.create_todo(args['title'], args['description'], args['due_date'])
        return todo.to_dict(), 201

    def put(self, todo_id):
        parser = reqparse.RequestParser()
        parser.add_argument('title')
        parser.add_argument('description')
        parser.add_argument('due_date', type=lambda x: datetime.strptime(x, '%Y-%m-%d'))
        parser.add_argument('completed', type=bool)
        args = parser.parse_args()

        todo = self.db.update_todo(todo_id, **args)
        if todo:
            return todo.to_dict()
        else:
            return {'error': 'Todo item not found'}, 404

    def delete(self, todo_id):
        if self.db.delete_todo(todo_id):
            return '', 204
        else:
            return {'error': 'Todo item not found'}, 404

class TodoProgress(Resource):
    def __init__(self, db):
        self.db = db

    def get(self):
        todos = self.db.get_all_todos()
        total = len(todos)
        completed = sum(1 for todo in todos if todo.completed)
        progress = (completed / total) * 100 if total else 0
        return {'total': total, 'completed': completed, 'progress': progress}

class TodoReminder(Resource):
    def __init__(self, db):
        self.db = db

    def get(self):
        todos = self.db.get_all_todos()
        due_soon = [todo for todo in todos if todo.due_date <= datetime.now() + timedelta(days=7) and not todo.completed]
        overdue = [todo for todo in todos if todo.due_date < datetime.now() and not todo.completed]
        return {'due_soon': [todo.to_dict() for todo in due_soon], 'overdue': [todo.to_dict() for todo in overdue]}

