    if not user:
        return jsonify({'error': 'User not found'}), 404

    total_items = user.items.count()
    completed_items = user.items.filter_by(completed=True).count()
    progress = (completed_items / total_items) * 100 if total_items else 0

    overdue_items = user.items.filter(TodoItem.due_date < datetime.now(), ~TodoItem.completed).count()
